# Add-k smoothed bigram
def build_smoothed_bigram(sentences, vocab, k=1.0):
    unigram_counts = Counter()
    bigram_counts  = defaultdict(Counter)
    for sent in sentences:
        tokens = ["<s>"] + sent + ["</s>"]
        for i, tok in enumerate(tokens):
            unigram_counts[tok] += 1
            if i > 0:
                bigram_counts[tokens[i-1]][tok] += 1

    V = len(vocab)
    def prob(prev, w):
        return (bigram_counts[prev][w] + k) / (unigram_counts[prev] + k * V)
    return prob

vocab = {"<s>", "</s>", "the", "cat", "sat", "on", "mat", "ate", "rat", "a"}
p = build_smoothed_bigram(corpus, vocab, k=1.0)
print(f"P(dog | the) [unseen] = {p('the','dog'):.4f}")   # non-zero now
print(f"P(cat | the) [seen]   = {p('the','cat'):.4f}")

def perplexity(sentences, prob_fn):
    total_log_prob = 0.0
    total_tokens   = 0
    for sent in sentences:
        tokens = ["<s>"] + sent + ["</s>"]
        for i in range(1, len(tokens)):
            p = prob_fn(tokens[i-1], tokens[i])
            total_log_prob += math.log(p + 1e-300)
            total_tokens   += 1
    return math.exp(-total_log_prob / total_tokens)

# Evaluate smoothed model on the same data (train PPL, for illustration)
train_ppl = perplexity(corpus, p)
print(f"Train perplexity: {train_ppl:.2f}")
